var e=[{id:`L2_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`전방에 침식체 군집 출현! 충돌까지 30초!`,JPN:`前方に侵食体の群れが出現！　遭遇まで30秒！`,ENG:`C.O. horde up ahead! Contact in 30 seconds!`,TWN:`前方有侵蝕體群出現！距離交會還剩30秒！`},stage:{bg:`PROLOGUE_02`,slots:{L:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`너무 가까워, 마리아 아줌마! 뿌리치긴 힘들겠어!`,JPN:`近すぎる、マリアおばさん！　撒くのは厳しいよ！`,ENG:`They're too close, Maria! We can't shake them off!`,TWN:`太近了，瑪麗亞大嬸！很難甩開啊！`},stage:{bg:`PROLOGUE_02`,slots:{L:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L5_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`함포 전방으로! 요격되지 않은 개체들은 그대로 돌파한다!`,JPN:`艦砲を前方に向けろ！　迎撃できなかった個体はそのまま突破する！`,ENG:`Cannons to the front! We push through any remaining C.O.s!`,TWN:`用艦炮開路！無法攔截的個體直接突破！`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`LOOK_REPLACER_NULL_NULL`,text:{KOREA:`하아…… 하아…….`,JPN:`はぁ……はぁ……`,ENG:`*Huff...* *Huff...*`,TWN:`哈啊……哈啊……`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LOOK_REPLACER_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`ALBERT_NPC_NULL_NULL`,text:{KOREA:`이마에 식은땀 좀 봐…….`,JPN:`顔に汗がすごいよ……`,ENG:`You're sweating...`,TWN:`你在流冷汗了……`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LOOK_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`ALBERT_NPC_NULL_NULL`,text:{KOREA:`기운내, 넘버 5! 넌 할 수 있어!`,JPN:`頑張って、ナンバー5！　あなたならできる！`,ENG:`Just a little more, number 5! You can do it!`,TWN:`加油，5號！你能行的！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LOOK_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MAVERICK_NPC_NULL_NULL`,text:{KOREA:`우리 엄마를 생각해서 힘내 줘! 내가 집에 안 들어가면 걱정돼서 잠도 못 주무신다고!`,JPN:`私のお母さんのためにも頑張ってくれ！　私が家に帰ってこないと心配で寝れない人なんだ！`,ENG:`Or at least keep going for my mom! She'll be worried sick if I don't come home!`,TWN:`至少為了我的媽媽加油吧！我要是不回家，她該擔心得睡不著覺了！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LOOK_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LOOK_REPLACER_NULL_NULL`,text:{KOREA:`너희들 입이 제일 문제야…….`,JPN:`もっとマシなセリフを言ってほしいものだ……`,ENG:`You two, hold your tongues...`,TWN:`你們的嘴才是最大的問題……`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LOOK_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`비, 비상! 비상!`,JPN:`ひ、非常状態！　非常状態！`,ENG:`D-Danger! Danger!`,TWN:`緊，緊急情況！緊急情況！`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L18_1`,type:`dialog`,speaker:`AKI_FREEDOM_NULL_NULL`,text:{KOREA:`격납고로 침식체들이 들어오려고 하고 있어요! 어떻게 좀 해 봐요!`,JPN:`格納庫に侵食体が入ってこようとしています！　なんとかしてください！`,ENG:`C.O.s are trying to come into the hangar! Do something!`,TWN:`侵蝕體正試圖闖入機庫！得想想辦法才行！`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`야! 호들갑 떨 시간에 한 마리라도 더 해치워!`,JPN:`おい！　騒いでいる暇があるなら、一匹でも多く倒せ！`,ENG:`Why don't you also try killing some then, huh?!`,TWN:`喂！有時間大呼小叫的，還是多幹掉一隻吧！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`사령관님, 함선에 침입하는 녀석들이 빠르게 늘어나고 있습니다.`,JPN:`司令官、艦船に侵入してくる敵が急速に増えています。`,ENG:`Commander, the number of C.O.s trying to break into the hangar is growing rapidly.`,TWN:`司令官，闖入艦船的侵蝕體正在快速增加。`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JAKE_DELTA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`거주 구역은 이미 격벽이 내려갔어. 얼마나 더 걸리는 거야?`,JPN:`居住エリアはすでに隔壁で封鎖したわ。あとどのくらいかかるの？`,ENG:`We've already lowered the walls in the residential area. How much longer will this take?`,TWN:`居住區已經放下隔離牆了。還需要多長時間？`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`COLLECTOR_NPC_NULL_NULL`,text:{KOREA:`우리 쪽 함선도 이제 곧 한계야. 더 이상 출력을 높이면 공중 분해되겠어.`,JPN:`こちらの艦船ももうすぐ限界だ。これ以上出力を上げたら空中分解する。`,ENG:`Our ship is also reaching its limit. If we increase the output anymore, we'll all get blown to bits.`,TWN:`我們的艦船也快到達極限了。如果繼續提高輸出，艦船會在空中解體。`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`COLLECTOR_NPC_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};